def tonelli_shanks(n, p):
    # 1. Verify if n is a quadratic residue using Euler's criterion
    if pow(n, (p - 1) // 2, p) != 1:
        return None  # No modular square root exists

    # 2. Factor out powers of 2 from p - 1
    # p - 1 = Q * 2^S
    s = 0
    q = p - 1
    while q % 2 == 0:
        q //= 2
        s += 1

    # 3. Handle the p = 3 (mod 4) case (fastest)
    if s == 1:
        return pow(n, (p + 1) // 4, p)

    # 4. Find a non-residue z
    z = 2
    while pow(z, (p - 1) // 2, p) != p - 1:
        z += 1

    # 5. Initialize variables
    m = s
    c = pow(z, q, p)
    t = pow(n, q, p)
    r = pow(n, (q + 1) // 2, p)

    # 6. Main loop
    while t != 0 and t != 1:
        # Find the smallest i, 0 < i < m, such that t^(2^i) = 1 (mod p)
        t2i = t
        i = 0
        for i in range(1, m):
            t2i = pow(t2i, 2, p)
            if t2i == 1:
                break
        
        # Update variables
        b = pow(c, 2**(m - i - 1), p)
        m = i
        c = pow(b, 2, p)
        t = (t * c) % p
        r = (r * b) % p

    return r



rt1 = tonelli_shanks(a, p); 
rt2 = p - rt1
print(f"FLAG: {min(rt1, rt2)}")